from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject from the first triple
    main_subject = triples[0].subject

    # Create a mapping of predicates to their values
    predicate_map = {}
    for t in triples:
        if t.predicate not in predicate_map:
            predicate_map[t.predicate] = []
        predicate_map[t.predicate].append(t.object)

    # Build sentence parts
    sentence_parts = []

    # Build main subject introduction
    intro_parts = [main_subject]

    # Add nationality/profession as modifier
    if 'nationality' in predicate_map:
        intro_parts.append(f"a {predicate_map['nationality'][0]} politician")
    elif 'profession' in predicate_map:
        intro_parts.append(f"a {predicate_map['profession'][0]}")

    if len(intro_parts) > 1:
        sentence_parts.append(f"{intro_parts[0]}, {intro_parts[1]},")
    else:
        sentence_parts.append(f"{intro_parts[0]},")

    # Build main clause with connected information
    main_clauses = []

    # Birth information
    birth_fragments = []
    if 'birthDate' in predicate_map:
        birth_fragments.append(f"born on {predicate_map['birthDate'][0]}")
    elif 'birthYear' in predicate_map:
        birth_fragments.append(f"born in {predicate_map['birthYear'][0]}")
    if 'birthPlace' in predicate_map:
        birth_fragments.append(f"in {predicate_map['birthPlace'][0]}")
    if birth_fragments:
        main_clauses.append(f"who was {' '.join(birth_fragments)}")

    # Career information
    if 'office' in predicate_map:
        main_clauses.append(f"served as {predicate_map['office'][0]}")
    if 'party' in predicate_map:
        main_clauses.append(f"for the {predicate_map['party'][0]} party")

    # Location information
    if 'country' in predicate_map:
        main_clauses.append(f"representing {predicate_map['country'][0]}")
    if 'state' in predicate_map:
        main_clauses.append(f"in {predicate_map['state'][0]}")
    if 'region' in predicate_map:
        main_clauses.append(f"covering {predicate_map['region'][0]}")

    # Military information
    if 'militaryBranch' in predicate_map:
        main_clauses.append(f"and served in the {predicate_map['militaryBranch'][0]}")
    if 'militaryRank' in predicate_map:
        main_clauses.append(f"with the rank of {predicate_map['militaryRank'][0]}")
    if 'unit' in predicate_map:
        main_clauses.append(f"assigned to {predicate_map['unit'][0]}")
    if 'battle' in predicate_map:
        main_clauses.append(f"and participated in the {predicate_map['battle'][0]}")

    # Death information
    death_fragments = []
    if 'deathDate' in predicate_map:
        death_fragments.append(f"died on {predicate_map['deathDate'][0]}")
    elif 'deathYear' in predicate_map:
        death_fragments.append(f"died in {predicate_map['deathYear'][0]}")
    if 'deathPlace' in predicate_map:
        death_fragments.append(f"in {predicate_map['deathPlace'][0]}")
    if death_fragments:
        main_clauses.append(f"and {' '.join(death_fragments)}")

    # Education information
    if 'almaMater' in predicate_map:
        main_clauses.append(f"and studied at {predicate_map['almaMater'][0]}")

    # Personal information
    if 'spouse' in predicate_map:
        main_clauses.append(f"and was married to {predicate_map['spouse'][0]}")
    if 'religion' in predicate_map:
        main_clauses.append(f"and practiced {predicate_map['religion'][0]}")
    if 'residence' in predicate_map:
        main_clauses.append(f"with residence at {predicate_map['residence'][0]}")

    # Political succession
    if 'predecessor' in predicate_map:
        main_clauses.append(f"and was preceded by {predicate_map['predecessor'][0]}")
    if 'successor' in predicate_map:
        main_clauses.append(f"and was succeeded by {predicate_map['successor'][0]}")
    if 'hasDeputy' in predicate_map:
        main_clauses.append(f"with {predicate_map['hasDeputy'][0]} as deputy")

    # Timeline information
    if 'activeYearsStartDate' in predicate_map:
        main_clauses.append(f"starting in {predicate_map['activeYearsStartDate'][0]}")
    if 'activeYearsEndDate' in predicate_map:
        main_clauses.append(f"until {predicate_map['activeYearsEndDate'][0]}")
    if 'serviceStartYear' in predicate_map:
        main_clauses.append(f"with service beginning in {predicate_map['serviceStartYear'][0]}")

    # Other information
    if 'award' in predicate_map:
        main_clauses.append(f"and received the {predicate_map['award'][0]}")
    if 'numberOfVotesAttained' in predicate_map:
        main_clauses.append(f"with {predicate_map['numberOfVotesAttained'][0]} votes")
    if 'inOfficeWhilePresident' in predicate_map:
        main_clauses.append(f"during the presidency of {predicate_map['inOfficeWhilePresident'][0]}")
    if 'inOfficeWhilePrimeMinister' in predicate_map:
        main_clauses.append(f"during the prime ministership of {predicate_map['inOfficeWhilePrimeMinister'][0]}")
    if 'inOfficeWhileVicePresident' in predicate_map:
        main_clauses.append(f"during the vice presidency of {predicate_map['inOfficeWhileVicePresident'][0]}")
    if 'inOfficeWhileGovernor' in predicate_map:
        main_clauses.append(f"during the governorship of {predicate_map['inOfficeWhileGovernor'][0]}")
    if 'inOfficeWhileMonarch' in predicate_map:
        main_clauses.append(f"during the reign of {predicate_map['inOfficeWhileMonarch'][0]}")

    # Combine all parts into one sentence
    if main_clauses:
        result = sentence_parts[0] + " " + ", ".join(main_clauses)
    else:
        result = sentence_parts[0].rstrip(",")

    return result + "."

# EVOLVE-BLOCK-END

